sql:
SELECT COUNT(*) AS movie_count
FROM movie_actors
WHERE actor_id = (SELECT actor_id FROM actors WHERE name = 'Tom Hanks');

SELECT m.title, m.vote_average
FROM movies m
WHERE m.vote_count = (
    SELECT MAX(vote_count)
    FROM movies
);

SELECT T1.writer_id, T1.name
FROM writers AS T1
INNER JOIN movie_writers AS T2 ON T1.writer_id = T2.writer_id;

SELECT COUNT(movie_id) 
FROM movie_writers 
WHERE writer_id = 0;
